#pragma once\\\\\\\\\\n#include <cstdint>\\\\\\\\\\n#include <cstddef>\\\\\\\\\\n// Correct interface; minimal signature, matches baseline\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\\\\\\\n    // Row-by-row/column-by-column processing to avoid surprises\\\\\n    for (size_t i = 0; i < M; ++i) {\\\\\\\\\n        for (size_t j = 0; j < K; j += 16) {\\\\\\\\\n            float cum[16] = {0.0f};\\\\\n            // For each output index, compute accum sum for corresponding B's entry\\\\\n            for (size_t k = 0; k < K; ++k) {\\\\\\n                // Decode B entry via packed integer; bit extraction\\\n                uint32_t b = B[k * (K/32) + j/32];\\\n                size_t bit = (b >> (j % 32)) & 1u;\\\n                float sgn = bit ? 1.0f : -1.0f;\\\n                size_t idx = j + k;\\\n                cum[ k % 16 ] += A[i * K + k] * sgn;\\\n            }\\\\n            // Store chunk once\\\n            for (size_t kp = 0; kp < 16; ++kp) {\\\\\\n                size_t out = j + kp;\\\n                if (out < K) C[ i*K + out ] = cum[ kp ];\\\n            }\\n        }\n    }\\n}